import { Link, useLocation } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

export default function Navbar() {
  const { user, logout } = useAuth();
  const { pathname } = useLocation();

  const navLink = (to, label, icon) => (
    <Link
      to={to}
      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-bold transition-all duration-200
        ${
          pathname === to
            ? "bg-blue-900 text-white"
            : "text-gray-300 hover:bg-gray-700 hover:text-white"
        }`}
    >
      <span>{icon}</span>
      {label}
    </Link>
  );

  return (
    <nav className="bg-[#2b293e] border-b border-gray-700 shadow-sm sticky top-[52px] z-40">
      <div className="max-w-5xl mx-auto px-4 h-14 flex items-center justify-between">
        <Link to="/" className="font-playfair text-2xl font-bold">
          SpeakUp
        </Link>

        <div className="flex items-center gap-1">
          {navLink("/", "Home", "🏠")}
          {navLink("/dashboard", "Progress", "📊")}
          {navLink("/words", "Words", "📚")}
          {navLink("/verbs", "Verbs", "📖")}
        </div>

        <div className="flex items-center gap-3">
          <div className="hidden sm:flex items-center gap-2">
            <div className="w-8 h-8 rounded-full bg-blue-900 text-white flex items-center justify-center font-extrabold text-sm">
              {user?.name?.[0]?.toUpperCase()}
            </div>
            <div className="text-xs">
              <p className="font-bold text-gray-300">{user?.name}</p>
              <p className="text-gray-400">🔥 {user?.streak} day streak</p>
            </div>
          </div>

          <button
            onClick={logout}
            className="text-xs border border-gray-500 px-3 py-1.5 rounded-lg text-gray-400 hover:border-red-300 hover:text-red-500 transition-all font-bold"
          >
            Logout
          </button>
        </div>
      </div>
    </nav>
  );
}
